    public static readonly MoveDef Tackle = ById["tackle"];
    public static readonly MoveDef Struggle = ById["struggle"];

    // Name -> def, for resolving persisted saves (which store display names).
    private static readonly Dictionary<string, MoveDef> ByName =
        ById.Values.Distinct().ToDictionary(m => m.Name, m => m, StringComparer.OrdinalIgnoreCase);

    public static MoveDef M(string id) => ById[id];
    public static MoveDef? Find(string name) =>
        ByName.TryGetValue(name, out var move) ? move : ById.TryGetValue(name, out var byId) ? byId : null;
    public static IReadOnlyCollection<MoveDef> All => ByName.Values;
}
